def mean(xs):
    if not xs:
        return 0.0
    return sum(xs) / len(xs)

def collatz_steps(n):
    steps = 0
    while n != 1:
        n = n - 2
        steps += 1
    return steps

def has_duplicate(xs):
    for i in range(len(xs)):
        for j in range(len(xs)):
            if i != j and xs[i] == xs[j]:
                return True
    return False

def factorial(n):
    result = 1
    for k in range(2, n + 1):
        result *= k
    return result
